SELECT DISTINCT RI.TBL_RETURN_INBOUND_ID, SP.TBL_SO_M_ID, SM.SO_NO, SM.SO_TYPE, DBO.F_COL_NM('A', 'COMM', 'SO_ORDR_TYPE', SM.SO_TYPE) AS SO_TYPE_NM, SM.SO_STAT_CD, DBO.F_COL_NM('A', 'COMM', 'SO_STAT_CD', SM.SO_STAT_CD) AS SO_STAT_CD_NM, SP.PROD_CD, SP.PROD_NM, RI.RETURN_QTY, ISNULL(RI.INBOUND_YN, 'N') AS INBOUND_YN, RI.INBOUND_DT, RI.INBOUND_USER, RI.INBOUND_TIME, RI.INBOUND_REMARK, ISNULL(RI.OUTBOUND_YN, 'N') AS OUTBOUND_YN, RI.OUTBOUND_DT, RI.OUTBOUND_USER, RI.OUTBOUND_TIME, RI.OUTBOUND_REMARK, ISNULL(RI.OUTBOUND_TARGET_YN, 'Y') AS OUTBOUND_TARGET_YN, SM.AGNT_CD, AG.AGNT_NM, SM.ACPT_ER, SM.ACPT_TEL1, SM.ACPT_TEL2, SM.POST_CD, SM.ADDR1, SM.ADDR2, SM.DC_CD, DC.DC_NM, SM.ORDR_INPT_DT, SM.RCPT_DT, SM.RQST_DT, SM.DLVY_CNFM_DT, SM.MALL_CD, SM.BRAND, SM.REF_SO_NO, SM.DLVY_RQST_MSG, SM.CUST_SPCL_TXT, SM.SAVE_TIME, UM.USER_NM AS INST_ER FROM TBL_SO_P SP INNER JOIN TBL_SO_M SM ON SP.TBL_SO_M_ID = SM.TBL_SO_M_ID INNER JOIN TBL_RETURN_INBOUND RI ON SP.TBL_SO_M_ID = RI.TBL_SO_M_ID AND SP.PROD_CD = RI.PROD_CD LEFT JOIN TBL_MTRL_M PM ON SP.PROD_CD = PM.MTRL_CD LEFT JOIN TBL_AGENCY_M AG ON SM.AGNT_CD = AG.AGNT_CD LEFT JOIN TBL_LGST_DC_M DC ON SM.DC_CD = DC.DC_CD LEFT JOIN TBL_INST_PLAN_M IP ON SM.TBL_SO_M_ID = IP.TBL_SO_M_ID LEFT JOIN TBL_USER_M UM ON IP.TBL_USER_M_ID = UM.TBL_USER_M_ID WHERE 1=1 AND SM.SO_STAT_CD NOT IN ('0000', '1900') AND SP.USE_YN = 'Y' AND SM.SO_TYPE IN ('2000', '3200', '4200', '9903', '9906', '6000') AND (PM.EXCHANGE_RETURN_EXCLUDE_YN IS NULL OR PM.EXCHANGE_RETURN_EXCLUDE_YN = 'N')
AND SM.ORDR_INPT_DT >= #{fromDt}
AND SM.ORDR_INPT_DT >= #{fromDt}
AND SM.DLVY_CNFM_DT >= #{fromDt}
AND SM.ORDR_INPT_DT >= #{fromDt}
AND SM.ORDR_INPT_DT <= #{toDt}
AND SM.ORDR_INPT_DT <= #{toDt}
AND SM.DLVY_CNFM_DT <= #{toDt}
AND SM.ORDR_INPT_DT <= #{toDt}
AND SM.AGNT_CD IN
#{agnt}
AND SM.DC_CD IN
#{dc}
AND SM.SO_NO IN
#{so}
AND SM.SO_TYPE IN
#{soType}
AND SM.ACPT_ER LIKE '%' + #{acptNm} + '%'
AND (SM.ACPT_TEL1 LIKE '%' + #{acptTel} + '%' OR SM.ACPT_TEL2 LIKE '%' + #{acptTel} + '%')
AND SP.PROD_CD IN
#{prod}
AND SP.PROD_NM LIKE '%' + #{prodNmSrch} + '%'
AND (SM.ADDR1 LIKE '%' + #{srchAddr} + '%' OR SM.ADDR2 LIKE '%' + #{srchAddr} + '%')
AND RI.INBOUND_YN = #{inboundStatus}
AND RI.OUTBOUND_YN = #{outboundStatus}
AND RI.OUTBOUND_TARGET_YN = #{outboundTarget}
ORDER BY SM.SAVE_TIME DESC

mapper.update:
UPDATE TBL_RETURN_INBOUND SET INBOUND_YN = 'N', INBOUND_DT = NULL, INBOUND_USER = NULL, INBOUND_TIME = NULL, INBOUND_REMARK = CONCAT(ISNULL(INBOUND_REMARK, ''), CASE WHEN INBOUND_REMARK IS NOT NULL AND INBOUND_REMARK != '' THEN ' | ' ELSE '' END, '[되돌리기] ', #{revertRemark}, ' (', #{processUser}, ', ', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss'), ')'), UPDT_USER = #{processUser}, UPDT_TIME = GETDATE() WHERE TBL_RETURN_INBOUND_ID IN
#{id}
AND INBOUND_YN = 'Y' -- 입고완료된 것만 되돌리기

UPDATE TBL_RETURN_INBOUND SET OUTBOUND_YN = 'N', OUTBOUND_DT = NULL, OUTBOUND_USER = NULL, OUTBOUND_TIME = NULL, OUTBOUND_REMARK = CONCAT(ISNULL(OUTBOUND_REMARK, ''), CASE WHEN OUTBOUND_REMARK IS NOT NULL AND OUTBOUND_REMARK != '' THEN ' | ' ELSE '' END, '[되돌리기] ', #{revertRemark}, ' (', #{processUser}, ', ', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm:ss'), ')'), UPDT_USER = #{processUser}, UPDT_TIME = GETDATE() WHERE TBL_RETURN_INBOUND_ID IN
#{id}
AND OUTBOUND_YN = 'Y' -- 반출완료된 것만 되돌리기
